[SubscribesTo(classStr(PrintMgmtDocType), delegateStr(PrintMgmtDocType, getDefaultReportFormatDelegate))]

public static void PrintMgmtDocType_getDefaultReportFormatDelegate(PrintMgmtDocumentType _docType, EventHandlerResult _result)
{
    if(curExt() == "H011")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesOrderInvoice:
                _result.result(ssrsReportStr(ETGSalesInvoice, ETGReport_H011));
                break;

        }
    }
    else if(curExt() == "C003")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesOrderInvoice:
                _result.result(ssrsReportStr(ETGSalesInvoice, ETGReport_C003));
                break;

        }
    }
    else if(curExt() == "S004")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesOrderInvoice:
                _result.result(ssrsReportStr(ETGSalesInvoice, ETGReport_S004));
                break;

        }
    }
    else if(curExt() == "O014")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesOrderInvoice:
                _result.result(ssrsReportStr(ETGSalesInvoice, ETGReport_O014));
                break;

        }
    }
    else if(curExt() == "O025")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesOrderInvoice:
                _result.result(ssrsReportStr(ETGSalesInvoice, ETGReport_O025));
                break;

        }
    }
    else
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesOrderInvoice:
                _result.result(ssrsReportStr(ETGSalesInvoice, ETGReport));
                break;
        }
    }

    if(curExt() == "O003")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesOrderPackingSlip:
                _result.result(ssrsReportStr(ETGSalesPackingSlip, ETGReport_O003));
                break;                
        }
    }   

    if(curExt() == "E016")
    {
        switch (_docType)
        {
            case PrintMgmtDocumentType::SalesFreeTextInvoice:
                _result.result(ssrsReportStr(ETGFreeTextInvoice, ETGReportE016));
                break;
        }
    }
}
